  doc.text("STATUS", margin + 55, y + 6);
  doc.text("PAYMENT METHOD", margin + 105, y + 6);
  doc.setTextColor(...dark);
  doc.setFont("helvetica", "bold");
  doc.setFontSize(10);
  const dateStr = new Date(order.createdAt).toLocaleDateString("en-US", {
    year: "numeric",
    month: "long",
    day: "numeric"
  });
