  doc.text("SIZE", colSize, y + 6);
  doc.text("COLOR", colColor, y + 6);
  doc.text("QTY", colQty, y + 6);
  doc.text("PRICE", colPrice, y + 6);
  doc.text("TOTAL", colTotal, y + 6, { align: "right" });
