    doc.text(`$${Number(item.unitPrice).toFixed(2)}`, colPrice, y + 7);
    const lineTotal = (item.qty * item.unitPrice).toFixed(2);
    doc.setFont("helvetica", "bold");
    doc.text(`$${lineTotal}`, colTotal, y + 7, { align: "right" });
